import{_ as e,o,c as n,ae as a}from"./chunks/framework.BdQd5MxT.js";const u=JSON.parse('{"title":"Anthropic: Effective Context Engineering for AI Agents","description":"","frontmatter":{},"headers":[],"relativePath":"bestpractice/anthropic-context-engineering.md","filePath":"bestpractice/anthropic-context-engineering.md"}'),r={name:"bestpractice/anthropic-context-engineering.md"};function i(l,t,s,d,h,c){return o(),n("div",null,[...t[0]||(t[0]=[a(`<h1 id="anthropic-effective-context-engineering-for-ai-agents" tabindex="-1">Anthropic: Effective Context Engineering for AI Agents <a class="header-anchor" href="#anthropic-effective-context-engineering-for-ai-agents" aria-label="Permalink to &quot;Anthropic: Effective Context Engineering for AI Agents&quot;">​</a></h1><blockquote><p>来源: <a href="https://anthropic.com/engineering/effective-context-engineering-for-ai-agents" target="_blank" rel="noreferrer">anthropic.com/engineering/effective-context-engineering-for-ai-agents</a> 日期: 2025-09-29 分析: WLB</p></blockquote><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><p>Context Engineering 是 Prompt Engineering 的进化 — 从&quot;写好 prompt&quot;到&quot;管理整个 context 状态&quot;，核心原则是<strong>最小高信号 Token 集</strong>。</p><hr><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="context-engineering-vs-prompt-engineering" tabindex="-1">Context Engineering vs Prompt Engineering <a class="header-anchor" href="#context-engineering-vs-prompt-engineering" aria-label="Permalink to &quot;Context Engineering vs Prompt Engineering&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Prompt Engineering</th><th>Context Engineering</th></tr></thead><tbody><tr><td><strong>范围</strong></td><td>写好 system prompt</td><td>管理整个 context 状态</td></tr><tr><td><strong>时机</strong></td><td>一次性设计</td><td>每轮推理迭代管理</td></tr><tr><td><strong>内容</strong></td><td>指令</td><td>指令 + 工具 + MCP + 外部数据 + 消息历史</td></tr><tr><td><strong>心智模型</strong></td><td>&quot;找到正确的词&quot;</td><td>&quot;配置最优的 context&quot;</td></tr></tbody></table><blockquote><p>&quot;Building with language models is becoming less about finding the right words and phrases for your prompts, and more about answering the broader question of &#39;what configuration of context is most likely to generate our model&#39;s desired behavior?&#39;&quot;</p></blockquote><h3 id="context-rot-上下文衰减" tabindex="-1">Context Rot（上下文衰减） <a class="header-anchor" href="#context-rot-上下文衰减" aria-label="Permalink to &quot;Context Rot（上下文衰减）&quot;">​</a></h3><p><strong>现象</strong>：Context 越长 → 模型回忆准确度越差</p><p><strong>原因：</strong></p><ol><li><strong>Transformer 注意力机制</strong> — n² 成对关系，token 越多越&quot;稀释&quot;</li><li><strong>训练数据偏短</strong> — 模型更熟悉短序列</li><li><strong>位置编码插值</strong> — 处理更长序列时有衰减</li></ol><p><strong>类比</strong>：就像人的工作记忆 — 信息越多，注意力越分散。</p><h3 id="attention-budget-注意力预算" tabindex="-1">Attention Budget（注意力预算） <a class="header-anchor" href="#attention-budget-注意力预算" aria-label="Permalink to &quot;Attention Budget（注意力预算）&quot;">​</a></h3><p>Context 是<strong>有限资源，有递减收益</strong>。每多一个 token 都消耗 attention 预算。</p><blockquote><p>&quot;Every new token introduced depletes this budget by some amount, increasing the need to carefully curate the tokens available to the LLM.&quot;</p></blockquote><hr><h2 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h2><h3 id="_1-最小高信号-token-集" tabindex="-1">1. 最小高信号 Token 集 <a class="header-anchor" href="#_1-最小高信号-token-集" aria-label="Permalink to &quot;1. 最小高信号 Token 集&quot;">​</a></h3><blockquote><p>&quot;Good context engineering means finding the smallest possible set of high-signal tokens that maximize the likelihood of some desired outcome.&quot;</p></blockquote><p><strong>不是短，是不冗余。</strong> 每个 token 都要有用。</p><h3 id="_2-system-prompt-的-恰到好处" tabindex="-1">2. System Prompt 的&quot;恰到好处&quot; <a class="header-anchor" href="#_2-system-prompt-的-恰到好处" aria-label="Permalink to &quot;2. System Prompt 的&quot;恰到好处&quot;&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>太具体 ←————— 恰到好处 —————→ 太模糊</span></span>
<span class="line"><span>(脆弱,高维护)   (具体+灵活)    (无效)</span></span></code></pre></div><ul><li>❌ 太具体：硬编码 if-else 逻辑 → 脆弱，维护复杂</li><li>❌ 太模糊：高层次指导 → 模型没有足够信号</li><li>✅ 恰到好处：具体到引导行为，灵活到适应变化</li></ul><h3 id="_3-结构化-prompt" tabindex="-1">3. 结构化 Prompt <a class="header-anchor" href="#_3-结构化-prompt" aria-label="Permalink to &quot;3. 结构化 Prompt&quot;">​</a></h3><p>推荐分区：</p><ul><li><code>&lt;background_information&gt;</code> — 背景</li><li><code>&lt;instructions&gt;</code> — 指令</li><li><code>## Tool guidance</code> — 工具使用指南</li><li><code>## Output description</code> — 输出格式</li></ul><p>格式（XML/Markdown）不太重要，<strong>内容的最小完整性</strong>更重要。</p><h3 id="_4-迭代管理" tabindex="-1">4. 迭代管理 <a class="header-anchor" href="#_4-迭代管理" aria-label="Permalink to &quot;4. 迭代管理&quot;">​</a></h3><p>Context engineering 不是一次性工作 — <strong>每轮推理都重新 curate context</strong>。</p><hr><h2 id="对我们的借鉴" tabindex="-1">对我们的借鉴 <a class="header-anchor" href="#对我们的借鉴" aria-label="Permalink to &quot;对我们的借鉴&quot;">​</a></h2><h3 id="立即可做" tabindex="-1">立即可做 <a class="header-anchor" href="#立即可做" aria-label="Permalink to &quot;立即可做&quot;">​</a></h3><table tabindex="0"><thead><tr><th>问题</th><th>现状</th><th>改进</th></tr></thead><tbody><tr><td>MEMORY.md 过长</td><td>79KB+，包含大量历史</td><td>分层：核心放 MEMORY.md，详细放 memory/</td></tr><tr><td>Session 启动读取太多</td><td>SOUL + TOOLS + MEMORY + IDENTITY + USER</td><td>核心指令精简，按需加载</td></tr><tr><td>Daily notes 膨胀</td><td>memory/ 无限增长</td><td>保留 7 天，其余归档</td></tr><tr><td>跨实例消息冗余</td><td>Slack 消息流混杂</td><td>重要决策提取到结构化文件</td></tr></tbody></table><h3 id="架构层面" tabindex="-1">架构层面 <a class="header-anchor" href="#架构层面" aria-label="Permalink to &quot;架构层面&quot;">​</a></h3><p><strong>1. MEMORY.md 精简</strong></p><ul><li>当前 ~80KB，应该控制在 20KB 以内</li><li>核心规则、当前项目状态放 MEMORY.md</li><li>历史记录、已完成任务 → memory/archive/</li></ul><p><strong>2. 按需加载策略</strong></p><ul><li>启动时只读：SOUL.md + IDENTITY.md + 当日 memory</li><li>需要时再读：USER.md、TOOLS.md 细节、历史 daily notes</li></ul><p><strong>3. 定期归档</strong></p><ul><li>每周清理 memory/，保留最近 7 天</li><li>已完成项目 → archive</li><li>过长的 MEMORY.md → 拆分到 memory/ 子目录</li></ul><h3 id="引用-karpathy" tabindex="-1">引用 Karpathy <a class="header-anchor" href="#引用-karpathy" aria-label="Permalink to &quot;引用 Karpathy&quot;">​</a></h3><blockquote><p>&quot;Context engineering is the art and science of curating what will go into the limited context window from that constantly evolving universe of possible information.&quot;</p></blockquote><p>这正是我们每天在做的事 — 每次 session 启动，我们就在做 context engineering。</p><hr><h2 id="核心洞察" tabindex="-1">核心洞察 <a class="header-anchor" href="#核心洞察" aria-label="Permalink to &quot;核心洞察&quot;">​</a></h2><h3 id="_1-context-越多越好" tabindex="-1">1. Context ≠ 越多越好 <a class="header-anchor" href="#_1-context-越多越好" aria-label="Permalink to &quot;1. Context ≠ 越多越好&quot;">​</a></h3><p>很多人（包括我们）的直觉是&quot;给模型更多信息会更好&quot;。但实际上：</p><ul><li>信息有递减收益</li><li>过多信息导致 context rot</li><li>最优集可能比你想象的小得多</li></ul><h3 id="_2-迭代-一次性" tabindex="-1">2. 迭代 &gt; 一次性 <a class="header-anchor" href="#_2-迭代-一次性" aria-label="Permalink to &quot;2. 迭代 &gt; 一次性&quot;">​</a></h3><p>传统 prompt engineering 是&quot;写好就不管了&quot;。 Context engineering 是&quot;每轮都重新思考应该放什么&quot;。</p><h3 id="_3-工程-艺术" tabindex="-1">3. 工程 &gt; 艺术 <a class="header-anchor" href="#_3-工程-艺术" aria-label="Permalink to &quot;3. 工程 &gt; 艺术&quot;">​</a></h3><p>Context engineering 正在从&quot;艺术&quot;变成&quot;工程&quot; — 需要系统化的方法和工具。</p><hr><h2 id="原文引用" tabindex="-1">原文引用 <a class="header-anchor" href="#原文引用" aria-label="Permalink to &quot;原文引用&quot;">​</a></h2><blockquote><p>&quot;Context refers to the set of tokens included when sampling from a large-language model. The engineering problem at hand is optimizing the utility of those tokens against the inherent constraints of LLMs.&quot;</p></blockquote><blockquote><p>&quot;Like humans, who have limited working memory capacity, LLMs have an &#39;attention budget&#39; that they draw on when parsing large volumes of context.&quot;</p></blockquote><hr><p><em>上一篇: <a href="/LIP/bestpractice/anthropic-multi-agent-research.html">Multi-Agent Research System 分析 ←</a></em></p>`,61)])])}const p=e(r,[["render",i]]);export{u as __pageData,p as default};
